// --- Controller Class ---
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.TextField;

public class ExampleController {
    @FXML
    private Label titleLabel;

    @FXML
    private TextField nameField;

    @FXML
    private TextField messageField;

    @FXML
    private Button submitButton;

    @FXML
    private Label resultLabel;

    // Called automatically after FXML is loaded
    @FXML
    private void initialize() {
        // Initialization code
        resultLabel.setText("Ready!");

        // Optional: Set up initial UI state
        submitButton.setDisable(true);

        // Add listeners
        nameField.textProperty().addListener((obs, oldVal, newVal) -> {
            checkFields();
        });
        messageField.textProperty().addListener((obs, oldVal, newVal) -> {
            checkFields();
        });
    }

    private void checkFields() {
        boolean hasName = !nameField.getText().trim().isEmpty();
        boolean hasMessage = !messageField.getText().trim().isEmpty();
        submitButton.setDisable(!(hasName && hasMessage));
    }

    // Event handler method
    @FXML
    private void handleSubmitButton() {
        String name = nameField.getText();
        String message = messageField.getText();
        resultLabel.setText("Hello, " + name + "! Your message: " + message);
        resultLabel.setStyle("-fx-text-fill: green; -fx-font-weight: bold;");

        // Clear fields
        nameField.clear();
        messageField.clear();
        submitButton.setDisable(true);
    }
}

// --- Main Application ---
import javafx.application.Application;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.Scene;
import javafx.stage.Stage;

public class FXMLApp extends Application {
    @Override
    public void start(Stage primaryStage) throws Exception {
        // Load FXML file
        FXMLLoader loader = new FXMLLoader(getClass().getResource("example.fxml"));
        Parent root = loader.load();

        Scene scene = new Scene(root, 400, 400);

        primaryStage.setTitle("FXML Example");
        primaryStage.setScene(scene);
        primaryStage.show();

        // Access controller if needed
        ExampleController controller = loader.getController();
        // Can call methods on controller
    }

    public static void main(String[] args) {
        launch(args);
    }
}

